mapper.select:
SELECT id, classroom_id, course_name, teacher_name,
       week_day, start_period, end_period, start_week, end_week, create_time
FROM course_schedule
WHERE classroom_id = #{classroomId}
  AND week_day = #{weekDay}
  AND start_week <= #{week}
  AND end_week >= #{week}
  AND start_period <= #{period}
  AND end_period >= #{period}
